sql:
SELECT AVG(fuel_efficiency) AS avg_fuel_efficiency, SUM(distance) AS total_distance
FROM fuel_consumption_history
WHERE vehicle_id = 1;

SELECT vehicle_id, SUM(distance) AS total_distance, AVG(fuel_efficiency) AS avg_fuel_efficiency
FROM trips
GROUP BY vehicle_id;
